use crate::api::*;
use std::collections::BinaryHeap;
use std::cmp::Reverse;
use parking_lot::RwLock;
use rayon::prelude::*;

pub struct VectorDB {
    // Store vectors flattened: vectors[i*dim..(i+1)*dim] for i-th vector
    vectors: RwLock<Vec<f32>>,
    ids: RwLock<Vec<u64>>,
    dim: usize,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            vectors: RwLock::new(Vec::new()),
            ids: RwLock::new(Vec::new()),
            dim: 128,
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        assert_eq!(vector.len(), self.dim, "Vector dimension mismatch");
        let mut vectors = self.vectors.write();
        let mut ids = self.ids.write();
        vectors.extend_from_slice(&vector);
        ids.push(id);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut vecs = self.vectors.write();
        let mut ids = self.ids.write();
        for (id, vector) in vectors {
            assert_eq!(vector.len(), self.dim, "Vector dimension mismatch");
            vecs.extend_from_slice(&vector);
            ids.push(id);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        assert_eq!(query.len(), self.dim, "Query dimension mismatch");
        let k = top_k as usize;
        let vectors = self.vectors.read();
        let ids = self.ids.read();
        let n = ids.len();
        if n == 0 {
            return Vec::new();
        }
        // Parallel iterate over chunks of vectors
        let chunk_size = (n + rayon::current_num_threads() - 1) / rayon::current_num_threads();
        let results: Vec<Vec<SearchResult>> = vectors
            .par_chunks(self.dim * chunk_size)
            .enumerate()
            .map(|(chunk_idx, chunk)| {
                let start_idx = chunk_idx * chunk_size;
                let end_idx = (start_idx + chunk.len() / self.dim).min(n);
                let local_ids = &ids[start_idx..end_idx];
                let mut heap = BinaryHeap::with_capacity(k + 1);
                for (i, &id) in local_ids.iter().enumerate() {
                    let vec_start = i * self.dim;
                    let vec_end = vec_start + self.dim;
                    let distance = crate::distance::l2_distance(query, &chunk[vec_start..vec_end]);
                    heap.push(Reverse((ordered_float::OrderedFloat(distance), id)));
                    if heap.len() > k {
                        heap.pop();
                    }
                }
                heap.into_sorted_vec().into_iter().map(|Reverse((dist, id))| SearchResult { id, distance: dist.into_inner() }).collect()
            })
            .collect();
        // Merge results from each chunk
        let mut global_heap = BinaryHeap::with_capacity(k + 1);
        for chunk_results in results {
            for result in chunk_results {
                global_heap.push(Reverse((ordered_float::OrderedFloat(result.distance), result.id)));
                if global_heap.len() > k {
                    global_heap.pop();
                }
            }
        }
        global_heap.into_sorted_vec().into_iter().map(|Reverse((dist, id))| SearchResult { id, distance: dist.into_inner() }).collect()
    }
}
"}">

pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), b.len());
    let mut sum = 0.0_f64;
    for (&ai, &bi) in a.iter().zip(b) {
        let diff = ai as f64 - bi as f64;
        sum += diff * diff;
    }
    sum.sqrt()
}
