use crate::api::*;
use ordered_float::OrderedFloat;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::cmp::Reverse;
use std::collections::BinaryHeap;

const DIM: usize = 128;

pub struct VectorDB {
    // flattened vectors, length = len * DIM
    vectors: RwLock<Vec<f32>>,
    ids: RwLock<Vec<u64>>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            vectors: RwLock::new(Vec::new()),
            ids: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        assert_eq!(vector.len(), DIM, "Vector dimension mismatch");
        let mut vectors = self.vectors.write();
        let mut ids = self.ids.write();
        vectors.extend_from_slice(&vector);
        ids.push(id);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut vecs = self.vectors.write();
        let mut ids = self.ids.write();
        // pre-allocate capacity
        vecs.reserve(count * DIM);
        ids.reserve(count);
        for (id, vector) in vectors {
            assert_eq!(vector.len(), DIM, "Vector dimension mismatch");
            vecs.extend_from_slice(&vector);
            ids.push(id);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        assert_eq!(query.len(), DIM, "Query dimension mismatch");
        let k = top_k as usize;
        let vectors = self.vectors.read();
        let ids = self.ids.read();
        let n = ids.len();
        if n == 0 || k == 0 {
            return Vec::new();
        }
        // If k >= n, we can just return all vectors sorted.
        // We'll parallelize across chunks.
        // Determine chunk size for good load balancing.
        let num_threads = rayon::current_num_threads();
        let chunk_size = (n + num_threads - 1) / num_threads;
        // Process each chunk in parallel, produce local top-k.
        let local_results: Vec<Vec<SearchResult>> = vectors
            .par_chunks(chunk_size * DIM)
            .zip(&ids.par_chunks(chunk_size))
            .map(|(vec_chunk, id_chunk)| {
                let mut heap = BinaryHeap::with_capacity(k + 1);
                for (idx, &id) in id_chunk.iter().enumerate() {
                    let start = idx * DIM;
                    let end = start + DIM;
                    let vec = &vec_chunk[start..end];
                    let dist = crate::distance::l2_distance(query, vec);
                    heap.push(Reverse((OrderedFloat(dist), id)));
                    if heap.len() > k {
                        heap.pop();
                    }
                }
                heap.into_sorted_vec()
                    .into_iter()
                    .map(|Reverse((OrderedFloat(dist), id))| SearchResult { id, distance: dist })
                    .collect()
            })
            .collect();
        // Merge local results
        let mut global_heap = BinaryHeap::with_capacity(k + 1);
        for local in local_results {
            for result in local {
                global_heap.push(Reverse((OrderedFloat(result.distance), result.id)));
                if global_heap.len() > k {
                    global_heap.pop();
                }
            }
        }
        global_heap
            .into_sorted_vec()
            .into_iter()
            .map(|Reverse((OrderedFloat(dist), id))| SearchResult { id, distance: dist })
            .collect()
    }
}
