use std::arch::x86_64::*;

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
#[target_feature(enable = "avx512dq")]
pub unsafe fn l2_squared_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), b.len());
    let len = a.len();
    let mut i = 0;
    // AVX-512 registers can hold 16 floats
    const LANES: usize = 16;
    let mut sums = _mm512_setzero_ps();
    while i + LANES <= len {
        let va = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff = _mm512_sub_ps(va, vb);
        // diff * diff + sums
        sums = _mm512_fmadd_ps(diff, diff, sums);
        i += LANES;
    }
    // horizontal sum across the SIMD register
    let sum = _mm512_reduce_add_ps(sums);
    // handle remaining elements
    let mut remaining = 0.0f32;
    while i < len {
        let diff = a[i] - b[i];
        remaining += diff * diff;
        i += 1;
    }
    (sum + remaining) as f64
}

