use crate::api::*;
use ordered_float::OrderedFloat;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 256;
const CLUSTERS_TO_SEARCH: usize = 20;

struct Cluster {
    ids: Vec<u64>,
    vectors: Vec<f32>, // flattened, len = ids.len() * DIM
}

pub struct VectorDB {
    // If centroids is empty, brute-force mode
    centroids: RwLock<Vec<Vec<f32>>>,
    clusters: RwLock<Vec<Cluster>>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            centroids: RwLock::new(Vec::new()),
            clusters: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        assert_eq!(vector.len(), DIM, "Vector dimension mismatch");
        let centroids = self.centroids.read();
        if centroids.is_empty() {
            // brute-force insertion not supported for single inserts in indexed mode
            // For simplicity, we'll just push to a temporary storage?
            // We'll not implement single insert for now; assume bulk_insert used.
            todo!("Single insert not implemented for indexed mode");
        } else {
            // Find nearest centroid
            let (nearest, _) = find_nearest_centroid(&vector, &centroids);
            let mut clusters = self.clusters.write();
            let cluster = &mut clusters[nearest];
            cluster.ids.push(id);
            cluster.vectors.extend_from_slice(&vector);
        }
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        if count == 0 {
            return 0;
        }
        // For first bulk insert, build index
        let mut centroids = self.centroids.write();
        let mut clusters = self.clusters.write();
        if centroids.is_empty() {
            // Build index using k-means on a sample of vectors
            let sample_size = 100_000.min(count);
            let sample: Vec<Vec<f32>> = vectors
                .iter()
                .take(sample_size)
                .map(|(_, v)| v.clone())
                .collect();
            *centroids = kmeans(&sample, NUM_CLUSTERS, 5);
            // Initialize clusters
            *clusters = (0..NUM_CLUSTERS)
                .map(|_| Cluster {
                    ids: Vec::new(),
                    vectors: Vec::new(),
                })
                .collect();
        }
        // Assign each vector to nearest centroid and store
        for (id, vector) in vectors {
            let (nearest, _) = find_nearest_centroid(&vector, &centroids);
            let cluster = &mut clusters[nearest];
            cluster.ids.push(id);
            cluster.vectors.extend_from_slice(&vector);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        assert_eq!(query.len(), DIM, "Query dimension mismatch");
        let k = top_k as usize;
        let centroids = self.centroids.read();
        let clusters = self.clusters.read();
        if centroids.is_empty() {
            // brute-force fallback (should not happen after index built)
            return brute_force_search(&clusters, query, k);
        }
        // Find nearest centroids
        let nearest_centroids = find_nearest_centroids(query, &centroids, CLUSTERS_TO_SEARCH);
        // Search vectors in those clusters
        let mut global_heap = BinaryHeap::with_capacity(k + 1);
        for &cluster_idx in &nearest_centroids {
            let cluster = &clusters[cluster_idx];
            let n = cluster.ids.len();
            if n == 0 {
                continue;
            }
            let vectors = &cluster.vectors;
            for (i, &id) in cluster.ids.iter().enumerate() {
                let start = i * DIM;
                let end = start + DIM;
                let vec = &vectors[start..end];
                let dist_sq = crate::distance::l2_squared_distance(query, vec);
                global_heap.push((OrderedFloat(dist_sq), id));
                if global_heap.len() > k {
                    global_heap.pop(); // remove largest distance
                }
            }
        }
        // Convert to results
        let mut results: Vec<SearchResult> = global_heap
            .into_vec()
            .into_iter()
            .map(|(OrderedFloat(dist_sq), id)| SearchResult {
                id,
                distance: dist_sq.sqrt(),
            })
            .collect();
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        results
    }
}

fn brute_force_search(clusters: &[Cluster], query: &[f32], k: usize) -> Vec<SearchResult> {
    let mut global_heap = BinaryHeap::with_capacity(k + 1);
    for cluster in clusters {
        let n = cluster.ids.len();
        if n == 0 {
            continue;
        }
        let vectors = &cluster.vectors;
        for (i, &id) in cluster.ids.iter().enumerate() {
            let start = i * DIM;
            let end = start + DIM;
            let vec = &vectors[start..end];
            let dist_sq = crate::distance::l2_squared_distance(query, vec);
            global_heap.push((OrderedFloat(dist_sq), id));
            if global_heap.len() > k {
                global_heap.pop();
            }
        }
    }
    let mut results: Vec<SearchResult> = global_heap
        .into_vec()
        .into_iter()
        .map(|(OrderedFloat(dist_sq), id)| SearchResult {
            id,
            distance: dist_sq.sqrt(),
        })
        .collect();
    results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
    results
}

fn find_nearest_centroid(vector: &[f32], centroids: &[Vec<f32>]) -> (usize, f64) {
    let mut best_idx = 0;
    let mut best_dist = f64::INFINITY;
    for (idx, centroid) in centroids.iter().enumerate() {
        let dist = crate::distance::l2_squared_distance(vector, centroid);
        if dist < best_dist {
            best_dist = dist;
            best_idx = idx;
        }
    }
    (best_idx, best_dist)
}

fn find_nearest_centroids(query: &[f32], centroids: &[Vec<f32>], limit: usize) -> Vec<usize> {
    let mut distances: Vec<(usize, f64)> = centroids
        .iter()
        .enumerate()
        .map(|(idx, centroid)| (idx, crate::distance::l2_squared_distance(query, centroid)))
        .collect();
    distances.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
    distances.into_iter().take(limit).map(|(idx, _)| idx).collect()
}

fn kmeans(vectors: &[Vec<f32>], k: usize, iterations: usize) -> Vec<Vec<f32>> {
    // Random initialization: pick k distinct vectors
    use rand::seq::index::sample;
    use rand::thread_rng;
    let mut rng = thread_rng();
    let mut centroids: Vec<Vec<f32>> = sample(&mut rng, vectors.len(), k)
        .iter()
        .map(|&i| vectors[i].clone())
        .collect();
    for _ in 0..iterations {
        // Assign each vector to nearest centroid
        let mut assignments: Vec<usize> = Vec::with_capacity(vectors.len());
        let mut counts = vec![0; k];
        let mut sums = vec![vec![0.0f32; DIM]; k];
        for vec in vectors {
            let mut best = 0;
            let mut best_dist = f64::INFINITY;
            for (idx, centroid) in centroids.iter().enumerate() {
                let dist = crate::distance::l2_squared_distance(vec, centroid);
                if dist < best_dist {
                    best_dist = dist;
                    best = idx;
                }
            }
            assignments.push(best);
            counts[best] += 1;
            for d in 0..DIM {
                sums[best][d] += vec[d];
            }
        }
        // Update centroids
        for i in 0..k {
            if counts[i] > 0 {
                for d in 0..DIM {
                    centroids[i][d] = sums[i][d] / counts[i] as f32;
                }
            }
        }
    }
    centroids
}

#[cfg(target_arch = "x86_64")]
use std::arch::x86_64::*;
#[cfg(target_arch = "x86_64")]
use std::arch::is_x86_feature_detected;

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
#[target_feature(enable = "avx512dq")]
unsafe fn l2_squared_distance_avx512_f32(a: &[f32], b: &[f32]) -> f32 {
    debug_assert_eq!(a.len(), b.len());
    let len = a.len();
    let mut i = 0;
    const LANES: usize = 16;
    let mut sums = _mm512_setzero_ps();
    while i + LANES <= len {
        let va = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff = _mm512_sub_ps(va, vb);
        sums = _mm512_fmadd_ps(diff, diff, sums);
        i += LANES;
    }
    // horizontal sum
    let mut sum_arr = [0.0f32; LANES];
    _mm512_storeu_ps(sum_arr.as_mut_ptr(), sums);
    let mut sum = 0.0f32;
    for &s in &sum_arr {
        sum += s;
    }
    // remaining
    while i < len {
        let diff = a[i] - b[i];
        sum += diff * diff;
        i += 1;
    }
    sum
}

fn l2_squared_distance_fallback_f32(a: &[f32], b: &[f32]) -> f32 {
    debug_assert_eq!(a.len(), b.len());
    let mut sum = 0.0_f32;
    for (&ai, &bi) in a.iter().zip(b) {
        let diff = ai - bi;
        sum += diff * diff;
    }
    sum
}

pub fn l2_squared_distance_f32(a: &[f32], b: &[f32]) -> f32 {
    #[cfg(target_arch = "x86_64")]
    {
        if is_x86_feature_detected!("avx512f") && is_x86_feature_detected!("avx512dq") {
            return unsafe { l2_squared_distance_avx512_f32(a, b) };
        }
    }
    l2_squared_distance_fallback_f32(a, b)
}

pub fn l2_squared_distance(a: &[f32], b: &[f32]) -> f64 {
    l2_squared_distance_f32(a, b) as f64
}

pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    l2_squared_distance_f32(a, b).sqrt() as f64
}

use crate::api::*;
use ordered_float::OrderedFloat;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 256;
const CLUSTERS_TO_SEARCH: usize = 16;

struct Cluster {
    ids: Vec<u64>,
    vectors: Vec<f32>, // flattened, len = ids.len() * DIM
}

pub struct VectorDB {
    // If centroids is empty, brute-force mode
    centroids: RwLock<Vec<Vec<f32>>>,
    clusters: RwLock<Vec<Cluster>>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            centroids: RwLock::new(Vec::new()),
            clusters: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        assert_eq!(vector.len(), DIM, "Vector dimension mismatch");
        let centroids = self.centroids.read();
        if centroids.is_empty() {
            // brute-force insertion not supported for single inserts in indexed mode
            // For simplicity, we'll just push to a temporary storage?
            // We'll not implement single insert for now; assume bulk_insert used.
            todo!("Single insert not implemented for indexed mode");
        } else {
            // Find nearest centroid
            let (nearest, _) = find_nearest_centroid(&vector, &centroids);
            let mut clusters = self.clusters.write();
            let cluster = &mut clusters[nearest];
            cluster.ids.push(id);
            cluster.vectors.extend_from_slice(&vector);
        }
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        if count == 0 {
            return 0;
        }
        // For first bulk insert, build index
        let mut centroids = self.centroids.write();
        let mut clusters = self.clusters.write();
        if centroids.is_empty() {
            // Build index using k-means on a sample of vectors
            let sample_size = 100_000.min(count);
            let sample: Vec<Vec<f32>> = vectors
                .iter()
                .take(sample_size)
                .map(|(_, v)| v.clone())
                .collect();
            *centroids = kmeans(&sample, NUM_CLUSTERS, 5);
            // Initialize clusters
            *clusters = (0..NUM_CLUSTERS)
                .map(|_| Cluster {
                    ids: Vec::new(),
                    vectors: Vec::new(),
                })
                .collect();
        }
        // Assign each vector to nearest centroid and store
        for (id, vector) in vectors {
            let (nearest, _) = find_nearest_centroid(&vector, &centroids);
            let cluster = &mut clusters[nearest];
            cluster.ids.push(id);
            cluster.vectors.extend_from_slice(&vector);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        assert_eq!(query.len(), DIM, "Query dimension mismatch");
        let k = top_k as usize;
        let centroids = self.centroids.read();
        let clusters = self.clusters.read();
        if centroids.is_empty() {
            // brute-force fallback (should not happen after index built)
            return brute_force_search(&clusters, query, k);
        }
        // Find nearest centroids
        let nearest_centroids = find_nearest_centroids(query, &centroids, CLUSTERS_TO_SEARCH);
        // Search vectors in those clusters
        let mut global_heap = BinaryHeap::with_capacity(k + 1);
        for &cluster_idx in &nearest_centroids {
            let cluster = &clusters[cluster_idx];
            let n = cluster.ids.len();
            if n == 0 {
                continue;
            }
            let vectors = &cluster.vectors;
            // Use SIMD distance calculation
            for (i, &id) in cluster.ids.iter().enumerate() {
                let start = i * DIM;
                let end = start + DIM;
                let vec = &vectors[start..end];
                let dist_sq = crate::distance::l2_squared_distance_f32(query, vec);
                global_heap.push((OrderedFloat(dist_sq), id));
                if global_heap.len() > k {
                    global_heap.pop(); // remove largest distance
                }
            }
        }
        // Convert to results
        let mut results: Vec<SearchResult> = global_heap
            .into_vec()
            .into_iter()
            .map(|(OrderedFloat(dist_sq), id)| SearchResult {
                id,
                distance: dist_sq.sqrt() as f64,
            })
            .collect();
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        results
    }
}

fn brute_force_search(clusters: &[Cluster], query: &[f32], k: usize) -> Vec<SearchResult> {
    let mut global_heap = BinaryHeap::with_capacity(k + 1);
    for cluster in clusters {
        let n = cluster.ids.len();
        if n == 0 {
            continue;
        }
        let vectors = &cluster.vectors;
        for (i, &id) in cluster.ids.iter().enumerate() {
            let start = i * DIM;
            let end = start + DIM;
            let vec = &vectors[start..end];
            let dist_sq = crate::distance::l2_squared_distance_f32(query, vec);
            global_heap.push((OrderedFloat(dist_sq), id));
            if global_heap.len() > k {
                global_heap.pop();
            }
        }
    }
    let mut results: Vec<SearchResult> = global_heap
        .into_vec()
        .into_iter()
        .map(|(OrderedFloat(dist_sq), id)| SearchResult {
            id,
            distance: dist_sq.sqrt() as f64,
        })
        .collect();
    results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
    results
}

fn find_nearest_centroid(vector: &[f32], centroids: &[Vec<f32>]) -> (usize, f32) {
    let mut best_idx = 0;
    let mut best_dist = f32::INFINITY;
    for (idx, centroid) in centroids.iter().enumerate() {
        let dist = crate::distance::l2_squared_distance_f32(vector, centroid);
        if dist < best_dist {
            best_dist = dist;
            best_idx = idx;
        }
    }
    (best_idx, best_dist)
}

fn find_nearest_centroids(query: &[f32], centroids: &[Vec<f32>], limit: usize) -> Vec<usize> {
    let mut distances: Vec<(usize, f32)> = centroids
        .iter()
        .enumerate()
        .map(|(idx, centroid)| (idx, crate::distance::l2_squared_distance_f32(query, centroid)))
        .collect();
    distances.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
    distances.into_iter().take(limit).map(|(idx, _)| idx).collect()
}

